import{_ as a,o as s,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"75. Staff Appraisals","description":"","frontmatter":{"title":"75. Staff Appraisals","eba":"Biomedical Engineers 2025-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/education-pd/75-staff-appraisals.md","filePath":"ebas/biomedical-engineers/education-pd/75-staff-appraisals.md"}'),o={name:"ebas/biomedical-engineers/education-pd/75-staff-appraisals.md"};function p(i,e,n,l,f,c){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_75-staff-appraisals" tabindex="-1">75. Staff Appraisals <a class="header-anchor" href="#_75-staff-appraisals" aria-label="Permalink to &quot;75. Staff Appraisals&quot;">​</a></h1><p>This clause does not apply to Employees at Peter MacCallum Cancer Centre.</p><p><strong>75.1</strong> Where a system of staff appraisals does not currently exist at a workplace, the Employer may implement and the Employees will participate in a performance appraisal process provided:</p><p><strong>(a)</strong> The Employer will first consult at the local level with Employees and/or their nominated representatives over a framework for staff appraisal process it is seeking to introduce;</p><p><strong>(b)</strong> The staff appraisal process is not used as a disciplinary tool;</p><p><strong>(c)</strong> The staff appraisal process is intended to allow genuine feedback by both Employer and Employee; and</p><p><strong>(d)</strong> The outcomes of the review are documented and confirmed and a written copy of the outcome is given to the Employee.</p>',7)])])}const _=a(o,[["render",p]]);export{m as __pageData,_ as default};
